	rep(i,s.size())update(i,P(s[i],i));

	string ans;

	rep(i,s.size()){

		int l=1,r=s.size();

		while(l!=r){

			int t=(l+r)/2;

			if(r-l==1)t=r;

			if(sum(t-1)<=k)l=t;

			else r=t-1;

		}

		P p=query(0,l,0,0,N);

		ans+=p.first;

		k-=sum(p.second);

		add(p.second+1,-1);

		update(p.second,P(INT_MAX,i));

	}

	cout<<ans<<endl;

}
